    tk.Frame(body, bg=BORDER_G, width=1).pack(side="left", fill="y")

    # MIDDLE: scrollable form
    mid_frm = tk.Frame(body, bg=BG_PANEL, width=420)
    mid_frm.pack(side="left", fill="y"); mid_frm.pack_propagate(False)
