    def _refresh_offsets(self, f=None):
        """Rebuild the OFFSETS UI rows from f.offsets. Clears and repopulates _offset_box."""
        if f is None: f = self.selected
        for w in self._offset_box.winfo_children(): w.destroy()
        self._offset_entries = []
        if not f:
            return
        offsets = getattr(f, "offsets", [])
        if not offsets:
            tk.Label(self._offset_box, text="None", bg=BG_PANEL, fg=TEXT_DIM,
                     font=("Helvetica", 9, "italic")).pack(anchor="w")
            return
        for i, off in enumerate(offsets):
            row = tk.Frame(self._offset_box, bg=BG_CARD, highlightthickness=1,
                           highlightbackground=BORDER_G, pady=2)
            row.pack(fill="x", pady=2)
            # X / Y row + delete button
            xy_row = tk.Frame(row, bg=BG_CARD); xy_row.pack(fill="x", padx=4)
            tk.Label(xy_row, text="x:", bg=BG_CARD, fg=TEXT_DIM,
                     font=("Helvetica", 9), width=2).pack(side="left")
            x_var = tk.StringVar(value=str(off.get("x", 0)))
            tk.Entry(xy_row, textvariable=x_var, bg=BG_PANEL, fg=TEXT,
                     font=("Helvetica", 9), relief="flat", width=5,
                     highlightthickness=1, highlightbackground=BORDER_G).pack(side="left", ipady=2, padx=(0, 6))
            tk.Label(xy_row, text="y:", bg=BG_CARD, fg=TEXT_DIM,
                     font=("Helvetica", 9), width=2).pack(side="left")
            y_var = tk.StringVar(value=str(off.get("y", 0)))
            tk.Entry(xy_row, textvariable=y_var, bg=BG_PANEL, fg=TEXT,
                     font=("Helvetica", 9), relief="flat", width=5,
                     highlightthickness=1, highlightbackground=BORDER_G).pack(side="left", ipady=2)
            del_btn = tk.Button(xy_row, text="✕", bg=BG_CARD, fg=RED, relief="flat",
                                font=("Georgia", 8), cursor="hand2", padx=3)
            del_btn.config(command=lambda idx=i: self._del_offset(idx))
            del_btn.pack(side="right")
            # trigger raw block
            tk.Label(row, text="trigger = {", bg=BG_CARD, fg=TEXT_DIM,
                     font=("Courier", 8), anchor="w").pack(fill="x", padx=4)
            trig_text = tk.Text(row, bg=BG_PANEL, fg=TEXT, insertbackground=BLUE,
                                font=("Courier", 8), height=3, relief="flat",
                                wrap="none", highlightthickness=1, highlightbackground=BORDER_G)
            trig_text.pack(fill="x", padx=4, pady=(0, 2))
            trig_text.insert("1.0", off.get("trigger", ""))
            tk.Label(row, text="}", bg=BG_CARD, fg=TEXT_DIM,
                     font=("Courier", 8), anchor="w").pack(fill="x", padx=4)
            self._offset_entries.append((x_var, y_var, trig_text))

    def _add_offset(self):
        """Add a blank offset entry to the selected focus and refresh UI."""
        if not self.selected: return
        self._save_offsets_to_focus()
        self.selected.offsets.append({"x": 0, "y": 0, "trigger": ""})
        self._refresh_offsets(self.selected)

    def _del_offset(self, idx):
        """Remove offset at idx from the selected focus and refresh UI."""
        if not self.selected: return
        self._save_offsets_to_focus()
        offs = getattr(self.selected, "offsets", [])
        if 0 <= idx < len(offs):
            offs.pop(idx)
        self._refresh_offsets(self.selected)

    def _save_offsets_to_focus(self):
        """Read current offset UI widgets and save to self.selected.offsets."""
        if not self.selected: return
        offs = []
        for x_var, y_var, trig_text in self._offset_entries:
            try: ox = int(x_var.get())
            except: ox = 0
            try: oy = int(y_var.get())
            except: oy = 0
            otrig = trig_text.get("1.0", "end").strip()
            offs.append({"x": ox, "y": oy, "trigger": otrig})
        self.selected.offsets = offs

