        _lbl("  Colon-style  [SOV:NameWithFlag]  — used by most vanilla decisions.")
        _lbl("  Dot-style    [SOV.GetName]        — used by some mods.")

        tok_row = tk.Frame(frm, bg=BG_PANEL)
